u=e("p",null,"Changes of key may also represent changes in mood. In many genres of music, moving from a lower key to a higher often indicates an increase in energy.",-1),p=e("p",null,'Change of key is not possible in the full chromatic or the twelve tone technique, as the modulatory space is completely filled; i.e., if every pitch is equal and ubiquitous there is nowhere else to go. Thus other differentiating methods are used, most importantly ordering and permutation. However, certain pitch formations may be used as a "tonic" or home area.',-1),y=e("h2",{id:"other-types",tabindex:"-1"},[o("Other types "),e("a",{class:"header-anchor",href:"#other-types","aria-hidden":"true"},"#")],-1),f=e("p",null,"Though modulation generally refers to changes of key, any parameter may be modulated, particularly in music of the 20th and 21st century. Metric modulation (known also as tempo modulation) is the most common, while timbral modulation (gradual changes in tone color), and spatial modulation (changing the location from which sound occurs) are also used.",-1),g=e("p",null,"Modulation may also occur from a single tonality to a polytonality, often by beginning with a duplicated tonic chord and modulating the chords in contrary motion until the desired polytonality is reached.",-1);function b(w,v,k,j,x,C){const t=i;return h(),n("div",null,[l,r(t,{video:"epqYft12nV4"}),m,c,u,p,y,f,g])}var _=a(d,[["render",b]]);export{D as __pageData,_ as default};
